// AUTO-GENERIERT von scripts/embed-studio.mjs – nicht editieren.
export const STUDIO_HTML = "<!doctype html>\n<html lang=\"de\">\n<head>\n<meta charset=\"utf-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<title>Claude Matrix Display – Animations-Editor</title>\n<style>\n  :root { --bg:#0E0F1A; --card:#1A1B2E; --accent:#9AA0FF; --txt:#E7E9F5; --mut:#7E84B8; }\n  * { box-sizing: border-box; }\n  body { margin:0; font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;\n         background:var(--bg); color:var(--txt); }\n  header { padding:16px 22px; border-bottom:1px solid #23253b; display:flex;\n           align-items:center; gap:12px; }\n  header h1 { font-size:17px; margin:0; font-weight:600; }\n  header .sub { color:var(--mut); font-size:13px; }\n  .wrap { display:flex; gap:22px; padding:22px; flex-wrap:wrap; }\n  .col { background:var(--card); border-radius:16px; padding:18px; }\n  .preview { width:300px; }\n  .controls { flex:1; min-width:320px; }\n  canvas { display:block; margin:0 auto; background:#0E0F1A; border-radius:14px; }\n  .tabs { display:flex; gap:8px; margin:14px 0; }\n  .tab { flex:1; padding:9px 0; text-align:center; border-radius:10px; cursor:pointer;\n         background:#23253b; color:var(--mut); font-size:13px; font-weight:600; user-select:none; }\n  .tab.active { background:var(--accent); color:#11121f; }\n  .row { display:flex; align-items:center; justify-content:space-between; gap:12px;\n         padding:9px 0; border-bottom:1px solid #23253b; }\n  .row:last-child { border-bottom:none; }\n  .row label { font-size:13px; color:var(--txt); }\n  input[type=text]{ background:#11121f; border:1px solid #2c2f4d; color:var(--txt);\n                    border-radius:8px; padding:6px 8px; width:130px; font-size:13px; }\n  input[type=color]{ width:38px; height:28px; border:none; background:none; padding:0; cursor:pointer; }\n  input[type=range]{ width:140px; }\n  select{ background:#11121f; border:1px solid #2c2f4d; color:var(--txt);\n          border-radius:8px; padding:6px 8px; font-size:13px; }\n  .btns { display:flex; gap:10px; margin-top:18px; flex-wrap:wrap; }\n  button { border:none; border-radius:10px; padding:11px 16px; font-size:13px; font-weight:600;\n           cursor:pointer; }\n  .primary { background:#3DDC97; color:#06210f; }\n  .ghost { background:#23253b; color:var(--txt); }\n  .toast { margin-top:12px; font-size:13px; color:var(--mut); min-height:18px; }\n  .hint { color:var(--mut); font-size:12px; margin-top:6px; }\n</style>\n</head>\n<body>\n<header>\n  <h1>🤖 Claude Matrix Display – Animations-Editor</h1>\n  <span class=\"sub\">Stelle pro Zustand ein, was der Roboter tut – live aufs Gerät.</span>\n</header>\n\n<div class=\"wrap\">\n  <div class=\"col preview\">\n    <canvas id=\"cv\" width=\"264\" height=\"240\"></canvas>\n    <div class=\"tabs\" id=\"tabs\">\n      <div class=\"tab active\" data-s=\"idle\">Leerlauf</div>\n      <div class=\"tab\" data-s=\"working\">Arbeitet</div>\n      <div class=\"tab\" data-s=\"waiting\">Bestätigung</div>\n      <div class=\"tab\" data-s=\"limit\">Limit</div>\n    </div>\n    <div class=\"hint\">Vorschau zeigt den oben gewählten Zustand. „Auf Gerät zeigen\"\n      schaltet den ESP32 testweise in diesen Zustand. Der Zustand <b>Limit</b>\n      wird im Betrieb automatisch von der Bridge gesetzt, sobald der Verbrauch\n      die Schwelle (Standard 85 %) erreicht – hier stellst du nur sein Aussehen ein.</div>\n    <button class=\"ghost\" id=\"showOnDevice\" style=\"margin-top:10px;width:100%\">Auf Gerät zeigen</button>\n  </div>\n\n  <div class=\"col controls\">\n    <div id=\"form\"></div>\n    <div class=\"btns\">\n      <button class=\"primary\" id=\"send\">An Gerät senden</button>\n      <button class=\"ghost\" id=\"download\">JSON herunterladen</button>\n      <button class=\"ghost\" id=\"reset\">Standard wiederherstellen</button>\n    </div>\n    <div class=\"toast\" id=\"toast\"></div>\n\n    <details id=\"settings\" style=\"margin-top:18px\">\n      <summary style=\"cursor:pointer;color:var(--accent);font-size:13px;font-weight:600\">⚙ Verbindung &amp; Limits</summary>\n      <div style=\"margin-top:10px\">\n        <div class=\"row\"><label>MQTT-URL</label><input type=\"text\" id=\"set_url\" placeholder=\"mqtt://192.168.1.10:1883\"></div>\n        <div class=\"row\"><label>MQTT-User</label><input type=\"text\" id=\"set_user\" placeholder=\"(optional)\"></div>\n        <div class=\"row\"><label>MQTT-Passwort</label><input type=\"text\" id=\"set_pass\" placeholder=\"(unverändert lassen)\"></div>\n        <div class=\"row\"><label>State-Topic</label><input type=\"text\" id=\"set_topic\"></div>\n        <div class=\"row\"><label>Session-Budget (Tokens)</label><input type=\"text\" id=\"set_sb\"></div>\n        <div class=\"row\"><label>Wochen-Budget (Tokens)</label><input type=\"text\" id=\"set_wb\"></div>\n        <div class=\"row\"><label>Wochen-Reset (ISO)</label><input type=\"text\" id=\"set_anchor\" placeholder=\"2026-06-02T00:00:00Z\"></div>\n        <div class=\"row\"><label>Limit-Schwelle (%)</label><input type=\"text\" id=\"set_limit\"></div>\n        <div class=\"btns\"><button class=\"primary\" id=\"saveSettings\">Einstellungen speichern</button></div>\n        <div class=\"hint\">Budget/Schwelle greifen sofort. MQTT-Änderungen verbinden neu.\n          Poll-Intervall-Änderungen erst nach Neustart.</div>\n      </div>\n    </details>\n  </div>\n</div>\n\n<script>\nconst DEFAULTS = {\n  version: 1,\n  states: {\n    idle:    { label:\"IDLE\",     bodyColor:\"#2B2D42\", eyeColor:\"#6C72A8\", eyeShape:\"circle\", eyeAnim:\"blink\", mouth:\"flat\",  spinner:false, spinnerColor:\"#3DDC97\", antenna:false, antennaColor:\"#FFB347\", bob:true,  speed:35, labelColor:\"#6C72A8\" },\n    working: { label:\"WORKING\",  bodyColor:\"#2B2D42\", eyeColor:\"#3DDC97\", eyeShape:\"circle\", eyeAnim:\"scan\",  mouth:\"smile\", spinner:true,  spinnerColor:\"#3DDC97\", antenna:true,  antennaColor:\"#3DDC97\", bob:true,  speed:80, labelColor:\"#3DDC97\" },\n    waiting: { label:\"CONFIRM?\", bodyColor:\"#402B2D\", eyeColor:\"#FFB347\", eyeShape:\"square\", eyeAnim:\"pulse\", mouth:\"o\",     spinner:false, spinnerColor:\"#FFB347\", antenna:true,  antennaColor:\"#FFB347\", bob:false, speed:55, labelColor:\"#FFB347\" },\n    limit:   { label:\"LIMIT!\",   bodyColor:\"#3A1620\", eyeColor:\"#FF5C5C\", eyeShape:\"square\", eyeAnim:\"pulse\", mouth:\"flat\",  spinner:false, spinnerColor:\"#FF5C5C\", antenna:true,  antennaColor:\"#FF5C5C\", bob:false, speed:90, labelColor:\"#FF5C5C\" },\n  }\n};\n\nlet anim = JSON.parse(JSON.stringify(DEFAULTS));\nlet current = \"idle\";\n\n// ---- Steuerelemente-Definition ----\nconst FIELDS = [\n  { k:\"label\",        t:\"text\",   l:\"Beschriftung\" },\n  { k:\"bodyColor\",    t:\"color\",  l:\"Körperfarbe\" },\n  { k:\"eyeColor\",     t:\"color\",  l:\"Augenfarbe\" },\n  { k:\"eyeShape\",     t:\"select\", l:\"Augenform\", opts:[[\"circle\",\"Kreis\"],[\"square\",\"Eckig\"]] },\n  { k:\"eyeAnim\",      t:\"select\", l:\"Augen-Animation\", opts:[[\"steady\",\"Ruhig\"],[\"blink\",\"Blinzeln\"],[\"scan\",\"Scannen\"],[\"pulse\",\"Pulsieren\"]] },\n  { k:\"mouth\",        t:\"select\", l:\"Mund\", opts:[[\"none\",\"Keiner\"],[\"smile\",\"Lächeln\"],[\"flat\",\"Strich\"],[\"o\",\"O\"]] },\n  { k:\"spinner\",      t:\"bool\",   l:\"Spinner (Ring)\" },\n  { k:\"spinnerColor\", t:\"color\",  l:\"Spinner-Farbe\" },\n  { k:\"antenna\",      t:\"bool\",   l:\"Antenne blinkt\" },\n  { k:\"antennaColor\", t:\"color\",  l:\"Antennen-Farbe\" },\n  { k:\"bob\",          t:\"bool\",   l:\"Auf-/Ab-Wippen\" },\n  { k:\"speed\",        t:\"range\",  l:\"Tempo\" },\n  { k:\"labelColor\",   t:\"color\",  l:\"Textfarbe\" },\n];\n\nfunction buildForm() {\n  const f = document.getElementById(\"form\");\n  const st = anim.states[current];\n  f.innerHTML = \"\";\n  for (const fd of FIELDS) {\n    const row = document.createElement(\"div\"); row.className = \"row\";\n    const lab = document.createElement(\"label\"); lab.textContent = fd.l; row.appendChild(lab);\n    let inp;\n    if (fd.t === \"text\") { inp = el(\"input\",{type:\"text\",value:st[fd.k]}); }\n    else if (fd.t === \"color\") { inp = el(\"input\",{type:\"color\",value:st[fd.k]}); }\n    else if (fd.t === \"range\") { inp = el(\"input\",{type:\"range\",min:0,max:100,value:st[fd.k]}); }\n    else if (fd.t === \"bool\") { inp = el(\"input\",{type:\"checkbox\"}); inp.checked = !!st[fd.k]; }\n    else if (fd.t === \"select\") {\n      inp = document.createElement(\"select\");\n      for (const [v,t] of fd.opts) { const o = el(\"option\",{value:v}); o.textContent = t; inp.appendChild(o); }\n      inp.value = st[fd.k];\n    }\n    inp.addEventListener(\"input\", () => {\n      st[fd.k] = (fd.t === \"bool\") ? inp.checked : (fd.t === \"range\") ? +inp.value : inp.value;\n    });\n    row.appendChild(inp); f.appendChild(row);\n  }\n}\nfunction el(tag, attrs){ const e=document.createElement(tag); for(const k in attrs) e[k]=attrs[k]; return e; }\n\n// ---- Tabs ----\ndocument.getElementById(\"tabs\").addEventListener(\"click\", (e) => {\n  const t = e.target.closest(\".tab\"); if(!t) return;\n  current = t.dataset.s;\n  document.querySelectorAll(\".tab\").forEach(x => x.classList.toggle(\"active\", x===t));\n  buildForm();\n});\n\n// ---- Canvas-Vorschau (spiegelt die Firmware-Semantik) ----\nconst cv = document.getElementById(\"cv\"), ctx = cv.getContext(\"2d\");\nfunction rr(x,y,w,h,r){ ctx.beginPath(); ctx.roundRect(x,y,w,h,r); }\nfunction draw(frame){\n  const s = anim.states[current];\n  const W = cv.width, H = cv.height, cx = W/2;\n  ctx.clearRect(0,0,W,H);\n  const spd = 0.4 + s.speed/60;\n  const bob = s.bob ? Math.sin(frame*0.08)*4 : 0;\n  const cy = 100 + bob;\n\n  // Spinner-Ring\n  if (s.spinner){\n    const a = (frame*(2+spd*4)) * Math.PI/180;\n    ctx.strokeStyle = s.spinnerColor; ctx.lineWidth = 4; ctx.beginPath();\n    ctx.arc(cx, cy, 72, a, a + 1.2); ctx.stroke();\n  }\n  // Körper\n  ctx.fillStyle = s.bodyColor; rr(cx-70, cy-60, 140, 120, 24); ctx.fill();\n  // Antenne\n  if (s.antenna){\n    const on = (frame%30)<15;\n    ctx.strokeStyle = s.antennaColor; ctx.globalAlpha = on?1:0.3; ctx.lineWidth=3;\n    ctx.beginPath(); ctx.moveTo(cx, cy-60); ctx.lineTo(cx, cy-74); ctx.stroke();\n    ctx.fillStyle = s.antennaColor; ctx.beginPath(); ctx.arc(cx, cy-78, 6, 0, 7); ctx.fill();\n    ctx.globalAlpha = 1;\n  }\n  // Augen\n  let w=26,h=26,xo=0;\n  if (s.eyeAnim===\"blink\" && (frame%90)<5) h=4;\n  else if (s.eyeAnim===\"scan\") xo = Math.sin(frame*0.12*spd)*9;\n  else if (s.eyeAnim===\"pulse\"){ const d=Math.sin(frame*0.18*spd)*4; w=26+d; h=26+d; }\n  ctx.fillStyle = s.eyeColor;\n  for (const dx of [-28,28]) eye(cx+dx+xo, cy-14, w, h, s.eyeShape);\n  // Mund\n  ctx.strokeStyle = s.eyeColor; ctx.fillStyle = s.eyeColor; ctx.lineWidth=4;\n  if (s.mouth===\"smile\"){ ctx.beginPath(); ctx.arc(cx, cy+8, 20, 0.18*Math.PI, 0.82*Math.PI); ctx.stroke(); }\n  else if (s.mouth===\"o\"){ ctx.beginPath(); ctx.arc(cx, cy+16, 10, 0, 7); ctx.stroke(); }\n  else if (s.mouth===\"flat\"){ rr(cx-16, cy+16, 32, 5, 2); ctx.fill(); }\n  // Label\n  ctx.fillStyle = s.labelColor; ctx.font = \"600 15px system-ui\"; ctx.textAlign=\"center\";\n  ctx.fillText(s.label || \"\", cx, cy+50);\n}\nfunction eye(x,y,w,h,shape){\n  if (shape===\"square\"){ rr(x-w/2, y-h/2, w, h, 6); ctx.fill(); }\n  else { ctx.beginPath(); ctx.ellipse(x,y,w/2,h/2,0,0,7); ctx.fill(); }\n}\nlet frame=0;\n(function loop(){ draw(frame++); requestAnimationFrame(loop); })();\n\n// ---- Aktionen ----\nfunction toast(msg){ document.getElementById(\"toast\").textContent = msg; }\nasync function post(url, body){\n  const r = await fetch(url, { method:\"POST\", headers:{\"Content-Type\":\"application/json\"}, body: JSON.stringify(body) });\n  return r.ok;\n}\ndocument.getElementById(\"send\").addEventListener(\"click\", async () => {\n  toast(\"sende…\");\n  const ok = await post(\"/config\", anim).catch(()=>false);\n  toast(ok ? \"✓ an Gerät gesendet & gespeichert\" : \"✗ Bridge nicht erreichbar (läuft node index.js?)\");\n});\ndocument.getElementById(\"showOnDevice\").addEventListener(\"click\", async () => {\n  const ok = await post(\"/preview\", { status: current }).catch(()=>false);\n  toast(ok ? \"✓ Gerät zeigt jetzt: \" + current : \"✗ Bridge nicht erreichbar\");\n});\ndocument.getElementById(\"download\").addEventListener(\"click\", () => {\n  const blob = new Blob([JSON.stringify(anim,null,2)], {type:\"application/json\"});\n  const a = el(\"a\",{href:URL.createObjectURL(blob),download:\"anim_config.json\"}); a.click();\n});\ndocument.getElementById(\"reset\").addEventListener(\"click\", () => {\n  anim = JSON.parse(JSON.stringify(DEFAULTS)); buildForm(); toast(\"Standardwerte geladen (noch nicht gesendet).\");\n});\n\n// ---- Einstellungen ----\nasync function loadSettings(){\n  try {\n    const r = await fetch(\"/settings\"); if(!r.ok) return;\n    const s = await r.json();\n    set(\"set_url\", s.mqtt?.url); set(\"set_user\", s.mqtt?.username); set(\"set_topic\", s.mqtt?.topic);\n    set(\"set_sb\", s.budgets?.sessionTokens); set(\"set_wb\", s.budgets?.weeklyTokens);\n    set(\"set_anchor\", s.weekly?.resetAnchorIso); set(\"set_limit\", s.limit?.pct);\n  } catch {}\n}\nfunction set(id,v){ const e=document.getElementById(id); if(e && v!=null) e.value=v; }\nfunction val(id){ return document.getElementById(id).value.trim(); }\ndocument.getElementById(\"saveSettings\").addEventListener(\"click\", async () => {\n  const body = {\n    mqtt: { url: val(\"set_url\"), username: val(\"set_user\"), topic: val(\"set_topic\") },\n    budgets: { sessionTokens: +val(\"set_sb\")||undefined, weeklyTokens: +val(\"set_wb\")||undefined },\n    weekly: { resetAnchorIso: val(\"set_anchor\") },\n    limit: { pct: +val(\"set_limit\")||undefined },\n  };\n  const pass = val(\"set_pass\"); if (pass) body.mqtt.password = pass;\n  const ok = await post(\"/settings\", body).catch(()=>false);\n  toast(ok ? \"✓ Einstellungen gespeichert\" : \"✗ Bridge nicht erreichbar\");\n});\n\n// ---- Initial laden ----\n(async () => {\n  await loadSettings();\n  try {\n    const r = await fetch(\"/config\");\n    if (r.ok) { const c = await r.json(); if (c && c.states) anim = c; }\n  } catch {}\n  // ältere Configs ohne \"limit\" nachrüsten\n  if (anim.states && !anim.states.limit) anim.states.limit = JSON.parse(JSON.stringify(DEFAULTS.states.limit));\n  buildForm();\n})();\n</script>\n</body>\n</html>\n";
